// src/pages/Homepage.jsx
import React from 'react';
import Navbar       from '../components/Navbar';
import Bubble       from '../components/Bubble';
import Services     from '../components/Services';
import ReadMoreBtn  from '../components/ReadMoreBtn';
import Journey      from '../components/Journey';
import LogoSlider   from '../components/LogoSlider';
import WorldMap     from '../components/WorldMap';
import Footer       from '../components/Footer';
import './Homepage.css'; // your new styles

// --- Static data lifted out of the component ---
const stats = [
  { count: '225+', label: 'Visual Identity' },
  { count: '180+', label: 'Marketing Strategy' },
  { count: '135+', label: 'Technical Project' },
  { count: '8+',   label: 'Experience Years' },
];

const serviceCards = [
  {
    title:  'Sarrdeh Care',
    text:   'Support, analysis, and management services that keep you informed …',
    accent: '#57B6B2',
  },
  {
    title:  'Sarrdeh Marketing',
    text:   'Services that make it easier to reach your target audience …',
    accent: '#FFD100',
  },
  {
    title:  'Sarrdeh Creative',
    text:   'Design services that let you showcase your brand …',
    accent: '#F32735',
  },
  {
    title:  'Sarrdeh Development',
    text:   'Software services that empower you to enhance your digital presence …',
    accent: '#1E6390',
  },
];

const steps = [
  { number: '01', title: 'Custom Consultation',        description: 'We begin with a session to understand your idea …' },
  { number: '02', title: 'Planning & Strategy',        description: 'We analyze your project and lay out a clear roadmap.' },
  { number: '03', title: 'Execution',                  description: 'We carry out the plans efficiently according to …' },
  { number: '04', title: 'Evaluation & Improvement',   description: 'We monitor results, analyze performance, and suggest …' },
];

const logos = [
  '/images/Atlas-logo-01_result.webp',
  '/images/A-Z-logo-01_result.webp',
  '/images/bliss-logo-01_result.webp',
  // …etc…
];

const markers = [
  {
    coords:    { t: '28%',  l: '18%' },
    country:   'Canada',
    flagUrl:   '/images/Canada-CA.svg',
    link:      '/projects/',
    ariaLabel: 'Canada – Corporate Stays',
    projects: [
      { logoUrl: '/images/corporate-stays-logo_result.webp', title: 'Corporate Stays', location: 'Toronto' },
    ],
  },
  // …other countries…
];

// --- Homepage component ---
export default function Homepage() {
  return (
    <main>
      <Navbar />

      {/* Hero / Banner */}
      <section id="hero" className="py-5 bg-hero">
        <div className="fixed-width mx-auto text-center position-relative">
          <h1 className="banner-font">
            Nowhere Else but <span className="text-teal">Success</span>
          </h1>
          <p className="home-banner-subtext">
            Start today and let our <span className="text-teal">team</span> handle the rest.
          </p>
          <ReadMoreBtn href="/contact-us">Book Your Free Consultation</ReadMoreBtn>
          <div id="particles-container">
            <canvas width={752} height={442} />
          </div>
        </div>
      </section>

      {/* Stats */}
      <section id="stats" className="py-5">
        <div className="container">
          <div className="row gy-4 justify-content-center">
            {stats.map((s, i) => (
              <Bubble key={i} count={s.count} label={s.label} />
            ))}
          </div>
        </div>
      </section>

      {/* In Short */}
      <section id="in-short" className="py-5">
        <div className="container text-center">
          <h2>
            <span className="text-teal">Sarrdeh</span> In Short
          </h2>
          <div className="row align-items-center mt-4">
            <div className="col-12 col-md-6 text-center">
              <img src="/images/logo.png" alt="Logo" className="img-fluid logo-img" />
            </div>
            <div className="col-12 col-md-6">
              <p>We are a dedicated <span className="text-teal">team</span> of strategic thinkers…</p>
              <p>Our mission is to empower your business through advanced…</p>
            </div>
          </div>
        </div>
      </section>

      {/* Services */}
      <section id="services" className="py-5 bg-dark">
        <div className="container">
          <Services cards={serviceCards} />
          <div className="text-center mt-4">
            <ReadMoreBtn href="/services">Read More Services</ReadMoreBtn>
          </div>
        </div>
      </section>

      {/* Journey */}
      <section id="journey" className="py-5">
        <div className="container text-center">
          <h2>Your Journey With Us</h2>
        </div>
        <Journey steps={steps} />
      </section>

      {/* Partners */}
      <section id="partners" className="py-5 bg-dark">
        <div className="container text-center mb-4">
          <h2>Partners In Success</h2>
        </div>
        <LogoSlider logos={logos} slideWidth={150} scrollSpeed={80} />
      </section>

      {/* Global Map */}
      <section id="global" className="py-5">
        <div className="container text-center mb-4">
          <h2><span className="text-teal">Sarrdeh</span> Global</h2>
          <p className="lead">From Syria to around the world… our reach grows every day.</p>
        </div>
        <WorldMap markers={markers} />
      </section>

      <Footer />
    </main>
  );
}
